import React, { useState } from 'react';
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
} from 'react-native';
import { COLORS, FONTS, SPACING, RADIUS, SHADOWS, POSITIONS } from '../../constants/theme';
import { Avatar, Badge, SkillBar } from '../../components/ui';
import Header from '../../components/Header';
import ActivityCard from '../../components/ActivityCard';
import { MOCK_PLAYER, MOCK_FEED } from '../../data/mockData';

interface ProfileScreenProps {
  onNavigate: (screen: string, params?: any) => void;
  onLogout: () => void;
}

export default function ProfileScreen({ onNavigate, onLogout }: ProfileScreenProps) {
  const player = MOCK_PLAYER;
  const [activeTab, setActiveTab] = useState('Hoạt động');

  const tabs = ['Hoạt động', 'Đội bóng', 'Highlights'];

  return (
    <View style={styles.container}>
      <Header />

      <ScrollView style={styles.scroll} showsVerticalScrollIndicator={false}>
        
        {/* Player Info Card */}
        <View style={styles.playerCard}>
          <TouchableOpacity style={styles.editBtn}>
            <Text style={styles.editBtnText}>✏️</Text>
          </TouchableOpacity>
          <View style={styles.avatarWrapper}>
            <Avatar name={player.fullName} size={88} />
          </View>
          <Text style={styles.playerName}>{player.fullName}</Text>
          <Text style={styles.playerMeta}>
            {POSITIONS[player.preferredPosition]} • {player.district}, {player.city}
          </Text>
        </View>

        {/* Stats Row */}
        <View style={styles.statsRow}>
          <View style={styles.statBox}>
            <Text style={styles.statNum}>12</Text>
            <Text style={styles.statLabel}>Bàn thắng</Text>
          </View>
          <View style={styles.statDivider} />
          <View style={styles.statBox}>
            <Text style={styles.statNum}>8</Text>
            <Text style={styles.statLabel}>Kiến tạo</Text>
          </View>
          <View style={styles.statDivider} />
          <View style={styles.statBox}>
            <Text style={styles.statNum}>{player.totalMatches}</Text>
            <Text style={styles.statLabel}>Số trận</Text>
          </View>
        </View>

        {/* Skills Section */}
        <View style={styles.skillsSection}>
           <Text style={styles.sectionTitle}>Chỉ số kỹ năng</Text>
           <View style={styles.skillsGrid}>
              <View style={styles.skillCol}>
                 <SkillBar label="Tốc độ" value={player.skills.speed} color={COLORS.primary} />
                 <SkillBar label="Chuyền bóng" value={player.skills.passing} color={COLORS.primary} />
              </View>
              <View style={styles.skillCol}>
                 <SkillBar label="Sút bóng" value={player.skills.shooting} color={COLORS.primary} />
                 <SkillBar label="Phòng ngự" value={player.skills.defending} color={COLORS.primary} />
              </View>
           </View>
        </View>

        {/* Tab Navigation */}
        <View style={styles.tabContainer}>
          {tabs.map(tab => (
            <TouchableOpacity 
              key={tab} 
              style={[styles.tabBtn, activeTab === tab && styles.tabBtnActive]}
              onPress={() => setActiveTab(tab)}
            >
              <Text style={[styles.tabText, activeTab === tab && styles.tabTextActive]}>
                {tab}
              </Text>
            </TouchableOpacity>
          ))}
        </View>

        {/* Tab Content */}
        <View style={styles.tabContent}>
           {activeTab === 'Hoạt động' && (
             <>
               {MOCK_FEED.map(activity => (
                 <ActivityCard key={activity.id} activity={activity} />
               ))}
             </>
           )}
           {activeTab === 'Đội bóng' && (
             <View style={styles.placeholderContent}>
                <Text style={styles.placeholderText}>Chưa có thông tin đội bóng.</Text>
             </View>
           )}
           {activeTab === 'Highlights' && (
             <View style={styles.placeholderContent}>
                <Text style={styles.placeholderText}>Chưa có video highlights.</Text>
             </View>
           )}
        </View>

        <View style={{ height: 100 }} />
      </ScrollView>
    </View>
  );
}

