// src/components/ActivityCard.tsx
import React from 'react';
import { View, Text, Image, StyleSheet, TouchableOpacity } from 'react-native';
import { COLORS, FONTS, SPACING, SHADOWS, RADIUS } from '../constants/theme';

interface ActivityCardProps {
  activity: any; // Type 'any' for mock flexibility right now
}

export default function ActivityCard({ activity }: ActivityCardProps) {
  // If it's a match result
  if (activity.type === 'match_result') {
    return (
      <View style={styles.card}>
        <View style={styles.header}>
          <View style={styles.teamBadge}>
            <View style={styles.avatarPlaceholder} />
            <Text style={styles.teamName}>{activity.homeTeam.name}</Text>
          </View>
          <Text style={styles.score}>{activity.score}</Text>
          <View style={styles.teamBadge}>
            <Text style={styles.teamName}>{activity.awayTeam.name}</Text>
            <View style={styles.avatarPlaceholder} />
          </View>
        </View>

        <View style={styles.metaRow}>
          <Text style={styles.metaText}>📍 {activity.location} • ⏰ {activity.time}</Text>
          <Text style={styles.motmText}>⭐ MOTM: {activity.motm}</Text>
        </View>

        {activity.image && (
          <Image source={{ uri: activity.image }} style={styles.media} resizeMode="cover" />
        )}

        <View style={styles.actionRow}>
          <TouchableOpacity style={styles.actionButton}>
            <Text style={styles.actionIcon}>👍 {activity.likes}</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.actionButton}>
            <Text style={styles.actionIcon}>💬 {activity.comments}</Text>
          </TouchableOpacity>
          <TouchableOpacity style={[styles.actionButton, styles.challengeBtn]}>
            <Text style={styles.challengeText}>⚔️ Challenge</Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  // If looking for opponent / generic post
  return (
    <View style={styles.card}>
      <View style={styles.headerGeneric}>
        <View style={styles.avatarPlaceholder} />
        <View style={styles.headerTextCol}>
          <Text style={styles.teamName}>{activity.team?.name || activity.userName || 'User'}</Text>
          <Text style={styles.metaText}>{activity.time}</Text>
        </View>
      </View>
      
      <Text style={styles.message}>{activity.message || activity.note}</Text>
      
      <View style={styles.metaRow}>
        <Text style={styles.metaText}>📍 {activity.location}</Text>
      </View>

      <View style={styles.actionRow}>
         <TouchableOpacity style={[styles.actionButton, styles.primaryBtn]}>
            <Text style={styles.primaryBtnText}>Liên hệ ngay</Text>
          </TouchableOpacity>
      </View>
    </View>
  );
}

